//-------------------------------------------------------------------------
// 조회 : 데이터를 조회한다.
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
  // 버전이 001일경우는 장부구분의 (자산비용)을 조회 하도록 코드값을 변경한다.
  if (lc_version.getValue() == "001" || lc_version.getValue() == "000") {
    // 일반일경우
    if (lc_srchBookClsCd.getValue() == "601") {
      dma_search.set("bookClsCd", "621");
      // 요약일경우
    } else if (lc_srchBookClsCd.getValue() == "602") {
      dma_search.set("bookClsCd", "622");
      // 상세일경우
    } else if (lc_srchBookClsCd.getValue() == "603") {
      dma_search.set("bookClsCd", "623");
    }
  }
  dma_search.set("fromDate", scwin.fromDate);
  dma_search.set("closeYm", ed_srchCloseYm.getValue());
  dma_search.set("ver", lc_version.getValue());
  dma_search.set("lowerDeptIncluYn", scwin.tldily); // 하위부서포함
  dma_search.set("acctDeptCd", scwin.p_acctDeptCd);
  dma_search.set("acctDeptLvl", scwin.tacctDeptLvl);
  dma_search.set("bookClsCd", lc_srchBookClsCd.getValue());
  dma_search.set("bizDomCd", ed_bizDomCd.getValue());
  dma_search.set("dpctYn", scwin.tDpct);
  dma_search.set("distYn", scwin.tDist); // 타법인포함
  dma_search.set("coCd", ed_coCd.getValue());
  dma_search.set("exceptionDeptYn", 0);
  dma_search.set("pageNo", 0);
  dma_search.set("clsCd", "");
  dma_search.set("CloseYyMm", ed_srchCloseYm.getValue());

  // eisAcctDeptCd : 0 일때 월별추이실적조회 , 1:법인별손익추이, 2:사업영역별손익추이

  dma_search.set("eisAcctDeptCd", "2");
  $c.sbm.execute($p, sbm_master);
};

//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = async function () {
  if (ds_master.getRowCount() == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
    return;
  }
  let gridColCount = 0;
  for (let i = 0; i < gr_master.getTotalCol(); i++) {
    //if(gr_master.getColumnVisible(i)==true){
    gridColCount++;
    //}
  }
  let str = $c.gus.cfGetFormatStr($p, ed_srchCloseYm.getValue().trim(), "####-##");
  let str1 = $c.gus.cfGetFormatStr($p, ed_srchCloseYm.getValue().trim(), "######");
  let str2 = ed_bizDomNm.getValue();
  let str3 = ed_srchAcctDeptNm.getValue();
  let str4 = lc_version.getValue();
  let vLcUnit = lc_unit.getText();
  let startRowIndex = 0;
  let infoArr = [{
    rowIndex: 0,
    colIndex: 0,
    colSpan: gridColCount,
    rowSpan: 1,
    text: ed_srchAcctDeptNm.getValue() + "(" + str1 + ")",
    //제목
    textAlign: "center",
    fontSize: 18,
    drawBorder: false,
    color: "black",
    backgroundColor: "#ffffff"
  }, {
    rowIndex: 2,
    colIndex: 0,
    colSpan: gridColCount,
    rowSpan: 1,
    text: "단위_" + lc_unit.getText(true),
    textAlign: "right",
    fontSize: 10,
    drawBorder: false,
    color: "black",
    backgroundColor: "#ffffff"
  }];
  const options = {
    fileName: "월별추이실적_" + ed_srchAcctDeptNm.getValue() + "_" + str1 + ".xlsx",
    sheetName: "월별추이실적_" + ed_srchAcctDeptNm.getValue() + "_" + str1,
    //hiddenVisible:"true",   //히든값(true : 포함, false : 미포함)
    startRowIndex: 4,
    startColumnIndex: 0,
    type: 1
  };
  await $c.data.downloadGridViewExcel($p, gr_master, options, infoArr);
};

